/**
 * us - N. Virginia, USA
 * eu - Frankfurt, Germany
 */
export declare type Region = 'us' | 'eu';
/**
 * city - resolution on a city level
 * full - resolution on a city level + ISP info using a live query to MaxMind service.
 * Will take longer to complete, because requires a separate network request.
 */
export declare type IPResolution = 'city' | 'full';
/**
 * Client agent configuration
 */
export interface Config {
    /**
     * Client token.
     * Required parameter.
     */
    client: string;
    /**
     * Region of the FingerprintJS Pro service API.
     * Required parameter.
     */
    region: Region;
    /**
     * Override cookie domain. Should be used when the agent runs on a subdomain.
     * @description If you're running your website on `foo.example.com`, but have another website
     * running on `bar.example.com`, use the `cookieDomain: "example.com"` to maximize the cross-identification effect.
     * According to: https://tools.ietf.org/html/rfc6265, leading dot is unnecessary and if you specify the cookieDomain
     * as `cookieDomain: "example.com"`, it will work on `example.com`, as well as on `foo.example.com` and `bar.example.com`.
     */
    cookieDomain?: string;
    /**
     * Override cookie key. Should only be used when the default key `_vid` conflicts with some of your existing cookies.
     */
    cookieKey?: string;
    /**
     * Override the default API endpoint for getting visitor data.
     */
    endpoint?: string;
    /**
     * Your custom TLS endpoint.
     */
    tlsEndpoint?: string;
    /**
     * @private
     * When browser doesn't support `requestIdleCallback` a `setTimeout` will be used.
     * When `setTimeout` is used, timeout value is `50ms`.
     * This number is only for Safari, Edge, and Internet Explorer, because Chrome/Blink based browsers support `requestIdleCallback`.
     * Don't set this number, unless you absolutely know what you're doing.
     */
    timeoutDelay?: number;
}
